#nullable enable // autogenerated

using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using PVZEngine.Entities;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [EntityBehaviourDefinition(VanillaContraptionNames.goldenDropper)]
    public class GoldenDropper : DispenserFamily
    {
        public GoldenDropper(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (!entity.IsEvoked())
            {
                ShootTick(entity);
                return;
            }
        }
        public override Entity? Shoot(Entity entity)
        {
            var shotSpeed = entity.GetShotVelocity().magnitude;
            foreach (var direction in shootDirections)
            {
                var dir = direction;
                dir.x *= entity.GetFacingX();
                var shootParams = entity.GetShootParams();
                shootParams.velocity = dir * shotSpeed;
                entity.ShootProjectile(shootParams);
            }
            return entity.ShootProjectile();
        }

        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);
            var rng = entity.RNG;
            for (int i = 0; i < 30; i++)
            {
                var xspeed = entity.GetFacingX() * rng.Next(10f, 18f);
                var yspeed = rng.Next(30f);
                var zspeed = rng.Next(-1.5f, 1.5f);
                var param = entity.GetShootParams();
                param.velocity = new Vector3(xspeed, yspeed, zspeed);
                entity.ShootProjectile(param);
            }
            entity.PlaySound(VanillaSoundID.launch);
        }

        public static Vector3[] shootDirections = new Vector3[]
        {
            new Vector3(1, 0, 0),   // œÚ«∞  
            new Vector3(0.5f, 0, 0.25f).normalized,   // œÚ◊Û…œ  
            new Vector3(0.5f, 0, -0.25f).normalized,    // œÚ”“…œ  
            //new Vector3(-1, 0, 0), // Back
            //new Vector3(0, 0, 1), // Up
            //new Vector3(0, 0, -1), // Down
            //new Vector3(0.866025f, 0, 0.5f).normalized, // Front-Up
            //new Vector3(0.866025f, 0, -0.5f).normalized, // Front-Down
        };
    }
}
